-- 插入辣椒醬系列分類
INSERT INTO categories (name, slug, description, imageUrl, sortOrder, isActive) VALUES
('辣椒醬系列', 'chili-sauce', '來點什麼獨家研發的台韓風味辣椒醬，融合台灣在地食材與韓式辛香料，打造獨特風味。', 'https://storage.manus.space/ordersome/categories/chili-sauce.jpg', 1, 1)
ON DUPLICATE KEY UPDATE name = VALUES(name);

-- 取得辣椒醬分類 ID 並插入商品
SET @category_id = (SELECT id FROM categories WHERE slug = 'chili-sauce' LIMIT 1);

INSERT INTO products (categoryId, name, slug, description, price, originalPrice, imageUrl, stock, isActive, isFeatured, sortOrder) VALUES
(@category_id, '台韓辣椒醬（單瓶）', 'chili-sauce-single', '來點什麼招牌台韓辣椒醬，融合台灣朝天椒與韓式辣椒粉，香辣不燥，適合拌飯、拌麵、沾醬。容量：250g', 180, 200, 'https://storage.manus.space/ordersome/products/chili-sauce-single.jpg', 100, 1, 1, 1),
(@category_id, '台韓辣椒醬（兩入組）', 'chili-sauce-double', '台韓辣椒醬超值兩入組，送禮自用兩相宜。每組包含 2 瓶 250g 辣椒醬，享優惠價。', 320, 360, 'https://storage.manus.space/ordersome/products/chili-sauce-double.jpg', 50, 1, 1, 2);

